Create CircuitBreaker and RetryPolicy infrastructure for reliability improvements

**Problem**: 53+ catch blocks swallow errors silently without retry logic.

**Fix**: Create foundational reliability components:

1. Create `src/shared/circuitBreaker.ts`:
```typescript
type CircuitState = 'closed' | 'open' | 'half-open';

export interface CircuitBreakerOptions {
  failureThreshold?: number;  // Default: 5
  successThreshold?: number;  // Default: 2  
  timeout?: number;          // Default: 60000 (1 minute)
}

export class CircuitBreaker {
  private state: CircuitState = 'closed';
  private failureCount = 0;
  private successCount = 0;
  private lastFailureTime: number | null = null;

  constructor(private options: CircuitBreakerOptions = {}) {
    this.options = {
      failureThreshold: 5,
      successThreshold: 2,
      timeout: 60000,
      ...options
    };
  }

  async execute<T>(fn: () => Promise<T>): Promise<T> {
    if (this.state === 'open') {
      if (this.shouldAttemptReset()) {
        this.state = 'half-open';
      } else {
        throw new Error('Circuit breaker is open');
      }
    }

    try {
      const result = await fn();
      this.onSuccess();
      return result;
    } catch (error) {
      this.onFailure();
      throw error;
    }
  }

  private onSuccess(): void {
    this.failureCount = 0;
    if (this.state === 'half-open') {
      this.successCount++;
      if (this.successCount >= (this.options.successThreshold ?? 2)) {
        this.state = 'closed';
        this.successCount = 0;
      }
    }
  }

  private onFailure(): void {
    this.failureCount++;
    this.lastFailureTime = Date.now();
    if (this.failureCount >= (this.options.failureThreshold ?? 5)) {
      this.state = 'open';
    }
  }

  private shouldAttemptReset(): boolean {
    if (!this.lastFailureTime) return true;
    return Date.now() - this.lastFailureTime >= (this.options.timeout ?? 60000);
  }

  getState(): CircuitState {
    return this.state;
  }
}
```

2. Create `src/shared/retryPolicy.ts`:
```typescript
export interface RetryOptions {
  maxAttempts?: number;      // Default: 3
  initialDelayMs?: number;   // Default: 1000
  maxDelayMs?: number;       // Default: 30000
  backoffMultiplier?: number;// Default: 2
}

export async function withRetry<T>(
  fn: () => Promise<T>,
  options: RetryOptions = {}
): Promise<T> {
  const opts = {
    maxAttempts: 3,
    initialDelayMs: 1000,
    maxDelayMs: 30000,
    backoffMultiplier: 2,
    ...options
  };

  let lastError: Error | undefined;
  let delay = opts.initialDelayMs;

  for (let attempt = 1; attempt <= opts.maxAttempts; attempt++) {
    try {
      return await fn();
    } catch (error) {
      lastError = error as Error;
      if (attempt < opts.maxAttempts) {
        await sleep(delay);
        delay = Math.min(delay * opts.backoffMultiplier, opts.maxDelayMs);
      }
    }
  }

  throw lastError;
}

function sleep(ms: number): Promise<void> {
  return new Promise(resolve => setTimeout(resolve, ms));
}
```

**Steps**:
1. Create src/shared/circuitBreaker.ts
2. Create src/shared/retryPolicy.ts  
3. Export them from src/shared/index.ts (or create one if not exists)
4. Verify compilation

This is Quick Win #5 - takes about 1 week.
